class Solution {
    public int numDecodings(String s) {
        return decode(s, 0);
    }

    private int decode(String s, int i) {
        if (i == s.length()) return 1;
        if (s.charAt(i) == '0') return 0;
        int ways = decode(s, i + 1);
        if (i + 1 < s.length() && Integer.parseInt(s.substring(i, i + 2)) <= 26) {
            ways += decode(s, i + 2);
        }
        return ways;
    }
}

class Solution {
    public int numDecodings(String s) {
        Integer[] memo = new Integer[s.length()];
        return decode(s, 0, memo);
    }

    private int decode(String s, int i, Integer[] memo) {
        if (i == s.length()) return 1;
        if (s.charAt(i) == '0') return 0;
        if (memo[i] != null) return memo[i];
        int ways = decode(s, i + 1, memo);
        if (i + 1 < s.length() && Integer.parseInt(s.substring(i, i + 2)) <= 26) {
            ways += decode(s, i + 2, memo);
        }
        memo[i] = ways;
        return ways;
    }
}

class Solution {
    public int numDecodings(String s) {
        if (s == null || s.isEmpty() || s.charAt(0) == '0') return 0;
        int n = s.length();
        int prev = 1, curr = 1;
        for (int i = 1; i < n; i++) {
            int temp = 0;
            if (s.charAt(i) != '0') temp = curr;
            int twoDigit = Integer.parseInt(s.substring(i - 1, i + 1));
            if (twoDigit >= 10 && twoDigit <= 26) {
                temp += prev;
            }
            prev = curr;
            curr = temp;
        }
        return curr;
    }
}
